import React, { useState, useEffect } from 'react';
import { BrowserRouter, Routes, Route, Link, useNavigate } from 'react-router-dom';
import HomePage from './pages/HomePage';
import LoginPage from './pages/LoginPage';
import RegisterPage from './pages/RegisterPage';
import UploadPage from './pages/UploadPage';
import VideoPlayerPage from './pages/VideoPlayerPage';
import MyVideosPage from './pages/MyVideosPage';
import './App.css';

function App() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [username, setUsername] = useState('');
  const navigate = useNavigate();

  useEffect(() => {
  const token = localStorage.getItem('access');
  const savedUsername = localStorage.getItem('username');

  if (token) {
    setIsAuthenticated(true);
    if (savedUsername) {
      setUsername(savedUsername);
    } else {
      // Если username не сохранён, пробуем получить из токена
      try {
        const payload = JSON.parse(atob(token.split('.')[1]));
        if (payload.username) {
          setUsername(payload.username);
          localStorage.setItem('username', payload.username);
        }
      } catch (e) {
        console.error('Ошибка декодирования токена:', e);
      }
    }
  }
  }, []);

  const handleLogout = () => {
    localStorage.removeItem('access');
    localStorage.removeItem('refresh');
    localStorage.removeItem('username');
    setIsAuthenticated(false);
    setUsername('');
    navigate('/');
  };

  return (
    <div className="app">
      <header className="header">
        <div className="logo">
          <Link to="/">🎬 ВидеоПлатформа</Link>
        </div>
        <div className="nav">
          {isAuthenticated ? (
            <>
              <Link to="/my-videos">📼 Мои видео</Link>
              <Link to="/upload">+ Загрузить</Link>
              <span className="username">👤 {username || 'Пользователь'}</span>
              <button onClick={handleLogout} className="logout-btn">Выйти</button>
            </>
          ) : (
            <>
              <Link to="/upload">+ Загрузить</Link>
              <Link to="/login">Войти</Link>
              <Link to="/register">Регистрация</Link>
            </>
          )}
        </div>
      </header>
      <main>
        <Routes>
          <Route path="/" element={<HomePage />} />
          <Route path="/login" element={<LoginPage setIsAuthenticated={setIsAuthenticated} setUsername={setUsername} />} />
          <Route path="/register" element={<RegisterPage />} />
          <Route path="/upload" element={<UploadPage />} />
          <Route path="/video/:id" element={<VideoPlayerPage />} />
          <Route path="/my-videos" element={<MyVideosPage />} />
        </Routes>
      </main>
    </div>
  );
}

export default App;
